<?php namespace App\Repositories\Timetable;use App\Repositories\BaseRepository;use App\Models\Timetable\TimetablePeriod;use Illuminate\Database\Eloquent\Collection;class TimetablePeriodRepository extends BaseRepository{    public function __construct(TimetablePeriod $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByTimetable(int $timetableId): Collection    {        return $this->findByField('timetable_id', $timetableId);    }    public function findByTeacher(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function findBySubject(int $subjectId): Collection    {        return $this->findByField('subject_id', $subjectId);    }    public function findByPeriodNumber(int $periodNumber): Collection    {        return $this->findByField('period_number', $periodNumber);    }    public function getByDayAndTeacher(string $day, int $employeeId): Collection    {        return $this->query()->whereHas('timetable', function ($q) use ($day) {                $q->where('day', $day);            })->where('employee_id', $employeeId)->get();    }    public function getPeriodsInTimeRange(string $startTime, string $endTime): Collection    {        return $this->query()->where('start_time', '>=', $startTime)->where('end_time', '<=', $endTime)->get();    }    public function updatePeriodOrder(int $timetableId, array $periodIds): bool    {        foreach ($periodIds as $index => $periodId) {            $this->update($periodId, [                'period_number' => $index + 1,                'timetable_id' => $timetableId,            ]);        }        return true;    }}